import{_ as e,o,c as t,a}from"./app.09e3ab02.js";const m=JSON.parse('{"title":"Supremacy Clarification, Jan 2022","description":"","frontmatter":{},"headers":[{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/supremacy_clarification_jan_2022.md","lastUpdated":1666920751000}'),n={name:"government/court-cases-precedents/supremacy_clarification_jan_2022.md"},i=a('<h1 id="supremacy-clarification-jan-2022" tabindex="-1">Supremacy Clarification, Jan 2022 <a class="header-anchor" href="#supremacy-clarification-jan-2022" aria-hidden="true">#</a></h1><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>Orinnari:</strong></p><blockquote><p>Would like to request a clarification from the High Justice regarding the interplay between Ololtic Law made via proposals and Council Law made via Charter Articles 2.4 and 2.9:</p></blockquote><blockquote><p>Council Law is by its nature considered inferior to Ololtic Law given than Ololtic proposals are the direct will of the people. Thus there is a question as to whether the Council can modify Ololtic Law, or whether Ololtic proposals, when modifying Council Law, it gets elevated to Ololtic Law status.</p></blockquote><blockquote><p>For example, Township Incorporation was introduced with Council Law 1.4, but then was modified by Proposal 8, so there&#39;s a question about whether Council Law can amend or repeal Township Incorporation should it need or want to.</p></blockquote><blockquote><p>But there&#39;s also the more general question as to whether Council Law can amend or repeal Ololtic Law.</p></blockquote><blockquote><p>Just discovered a similar situation with Recall Elections.</p></blockquote><blockquote><p>Council Act 7.1 establishes Recall Elections, but Proposal 30 (#passed-proposal-recall-elections-ammendments) amended 7.1, so the same question arises about whether the Council is now unable to amend Recall Elections.</p></blockquote><p><strong>SpaceVolcano:</strong></p><blockquote><p>Orinnari, the way the court would handle a case if a conflict arose would be weighted one way or another dependant upon the situation in which the case arose. As for the ability to amend or not amend each others laws we currently do not have a clear text on the books saying what is or isn&#39;t allowed. The council is allowed to create and change laws as well as the Ololtic. By nature Olotlic law does carry the weight of the people, however the council is elected by the people and carries the peoples weight through represention. The interplay between the two has been and currently seems to be acceptable, checking each other&#39;s power and if an unacceptable exchange were to happen between the two bodies over any proposal or amendment it would fall to the court. Any further clarification would have to come from an amendment to the constitution passed by the Ololtic with a written clause.</p></blockquote><blockquote><p>Brief version currently allowed either way, Ololtic can amend council, council can amend ololtic</p></blockquote>',12),c=[i];function r(l,s,h,d,p,u){return o(),t("div",null,c)}const b=e(n,[["render",r]]);export{m as __pageData,b as default};
